args.ReplacementContent:
"                      // DISC status parsing
                      const phoneStr = fullApp.candidate_phone || '';
                      const parsedData = parseCandidatePhoneData(phoneStr);
                      let discStatus = 'NONE';
                      let D = 0, I = 0, S = 0, C = 0;
                      if (parsedData.disc) {
                        const discVal = parsedData.disc;
                        if (discVal === 'PENDING') {
                          discStatus = 'PENDING';
                        } else if (discVal.startsWith('COMPLETED===')) {
                          discStatus = 'COMPLETED';
                          const scores = discVal.replace('COMPLETED===', '').split(',').map(Number);
                          D = scores[0] || 0;
                          I = scores[1] || 0;
                          S = scores[2] || 0;
                          C = scores[3] || 0;
                        }
                      }

                      return {
                        ...applicant,
                        fullApp,
                        matchScore,
                        normalizedStatus,
                        discStatus,
                        notes: parsedData.notes,
                        D, I, S, C
                      };"

